class CalendarListEntry(BaseModel):
    access_role: Annotated[str | None, Field(alias='accessRole')] = None
    """
    The effective access role that the authenticated user has on the calendar. Read-only. Possible values are:
    - "freeBusyReader" - Provides read access to free/busy information.
    - "reader" - Provides read access to the calendar. Private events will appear to users with reader access, but event details will be hidden.
    - "writer" - Provides read and write access to the calendar. Private events will appear to users with writer access, and event details will be visible.
    - "owner" - Provides manager access to the calendar. This role has all of the permissions of the writer role with the additional ability to see and modify access levels of other users.
    Important: the owner role is different from the calendar's data owner. A calendar has a single data owner, but can have multiple users with owner role.
    """
    auto_accept_invitations: Annotated[
        bool | None, Field(alias='autoAcceptInvitations')
    ] = None
    """
    Whether this calendar automatically accepts invitations. Only valid for resource calendars. Read-only.
    """
    background_color: Annotated[str | None, Field(alias='backgroundColor')] = None
    """
    The main color of the calendar in the hexadecimal format "#0088aa". This property supersedes the index-based colorId property. To set or change this property, you need to specify colorRgbFormat=true in the parameters of the insert, update and patch methods. Optional.
    """
    color_id: Annotated[str | None, Field(alias='colorId')] = None
    """
    The color of the calendar. This is an ID referring to an entry in the calendar section of the colors definition (see the colors endpoint). This property is superseded by the backgroundColor and foregroundColor properties and can be ignored when using these properties. Optional.
    """
    conference_properties: Annotated[
        ConferenceProperties | None, Field(alias='conferenceProperties')
    ] = None
    """
    Conferencing properties for this calendar, for example what types of conferences are allowed.
    """
    data_owner: Annotated[str | None, Field(alias='dataOwner')] = None
    """
    The email of the owner of the calendar. Set only for secondary calendars. Read-only.
    """
    default_reminders: Annotated[
        list[EventReminder] | None, Field(alias='defaultReminders')
    ] = None
    """
    The default reminders that the authenticated user has for this calendar.
    """
    deleted: bool | None = 'false'
    """
    Whether this calendar list entry has been deleted from the calendar list. Read-only. Optional. The default is False.
    """
    description: str | None = None
    """
    Description of the calendar. Optional. Read-only.
    """
    etag: str | None = None
    """
    ETag of the resource.
    """
    foreground_color: Annotated[str | None, Field(alias='foregroundColor')] = None
    """
    The foreground color of the calendar in the hexadecimal format "#ffffff". This property supersedes the index-based colorId property. To set or change this property, you need to specify colorRgbFormat=true in the parameters of the insert, update and patch methods. Optional.
    """
    hidden: bool | None = 'false'
    """
    Whether the calendar has been hidden from the list. Optional. The attribute is only returned when the calendar is hidden, in which case the value is true.
    """
    id: str | None = None
    """
    Identifier of the calendar.
    """
    kind: str | None = 'calendar#calendarListEntry'
    """
    Type of the resource ("calendar#calendarListEntry").
    """
    location: str | None = None
    """
    Geographic location of the calendar as free-form text. Optional. Read-only.
    """
    notification_settings: Annotated[
        NotificationSettings | None, Field(alias='notificationSettings')
    ] = None
    """
    The notifications that the authenticated user is receiving for this calendar.
    """
    primary: bool | None = 'false'
    """
    Whether the calendar is the primary calendar of the authenticated user. Read-only. Optional. The default is False.
    """
    selected: bool | None = 'false'
    """
    Whether the calendar content shows up in the calendar UI. Optional. The default is False.
    """
    summary: str | None = None
    """
    Title of the calendar. Read-only.
    """
    summary_override: Annotated[str | None, Field(alias='summaryOverride')] = None
    """
    The summary that the authenticated user has set for this calendar. Optional.
    """
    time_zone: Annotated[str | None, Field(alias='timeZone')] = None
    """
    The time zone of the calendar. Optional. Read-only.
    """


